import pyotp
import qrcode
import base64
import os
from flask import Flask, request, jsonify

app = Flask(__name__)

def generate_totp_secret():
    return pyotp.random_base32()

def generate_qr_code(secret, username):
    totp_uri = pyotp.totp.TOTP(secret).provisioning_uri(name=username, issuer_name="YourApp")
    qr = qrcode.make(totp_uri)
    qr.save(f"{username}_qrcode.png")

def validate_totp(secret, token):
    totp = pyotp.TOTP(secret)
    return totp.verify(token)

@app.route('/generate', methods=['POST'])
def generate():
    username = request.json.get('username')
    if not username:
        return jsonify({'error': 'Username is required'}), 400
    secret = generate_totp_secret()
    generate_qr_code(secret, username)
    return jsonify({'secret': secret})

@app.route('/validate', methods=['POST'])
def validate():
    secret = request.json.get('secret')
    token = request.json.get('token')
    if not secret or not token:
        return jsonify({'error': 'Secret and token are required'}), 400
    if validate_totp(secret, token):
        return jsonify({'status': 'success'})
    else:
        return jsonify({'status': 'failure'}), 401

if __name__ == '__main__':
    app.run(ssl_context='adhoc')